139: func unauthorized(c *contextmodel.ReqContext) {
140: 	if c.IsApiRequest() {
141: 		c.WriteErrOrFallback(http.StatusUnauthorized, http.StatusText(http.StatusUnauthorized), c.LookupTokenErr)
142: 		return
143: 	}
144: 
145: 	if !c.UseSessionStorageRedirect {
146: 		writeRedirectCookie(c)
147: 	}
148: 
149: 	var tokenRotationErr authn.TokenNeedsRotationError
150: 	if errors.As(c.LookupTokenErr, &tokenRotationErr) {
151: 		if !c.UseSessionStorageRedirect {
152: 			c.Redirect(setting.AppSubUrl + "/user/auth-tokens/rotate")
153: 			return
154: 		}
155: 		c.Redirect(setting.AppSubUrl + "/user/auth-tokens/rotate" + getRedirectToQueryParam(c))
156: 		return
157: 	}
158: 
159: 	if !c.UseSessionStorageRedirect {
160: 		c.Redirect(setting.AppSubUrl + "/login")
161: 		return
162: 	}
163: 
164: 	c.Redirect(setting.AppSubUrl + "/login" + getRedirectToQueryParam(c))
165: }
