167: func tokenRevoked(c *contextmodel.ReqContext, err *usertoken.TokenRevokedError) {
168: 	if c.IsApiRequest() {
169: 		c.JSON(http.StatusUnauthorized, map[string]any{
170: 			"message": "Token revoked",
171: 			"error": map[string]any{
172: 				"id":                    "ERR_TOKEN_REVOKED",
173: 				"maxConcurrentSessions": err.MaxConcurrentSessions,
174: 			},
175: 		})
176: 		return
177: 	}
178: 
179: 	if !c.UseSessionStorageRedirect {
180: 		writeRedirectCookie(c)
181: 		c.Redirect(setting.AppSubUrl + "/login")
182: 		return
183: 	}
184: 
185: 	c.Redirect(setting.AppSubUrl + "/login" + getRedirectToQueryParam(c))
186: }
