188: func writeRedirectCookie(c *contextmodel.ReqContext) {
189: 	redirectTo := c.Req.RequestURI
190: 	if setting.AppSubUrl != "" && !strings.HasPrefix(redirectTo, setting.AppSubUrl) {
191: 		redirectTo = setting.AppSubUrl + c.Req.RequestURI
192: 	}
193: 
194: 	// remove any forceLogin=true params
195: 	redirectTo = removeForceLoginParams(redirectTo)
196: 
197: 	cookies.WriteCookie(c.Resp, "redirect_to", url.QueryEscape(redirectTo), 0, nil)
198: }
