200: func getRedirectToQueryParam(c *contextmodel.ReqContext) string {
201: 	redirectTo := c.Req.RequestURI
202: 	if setting.AppSubUrl != "" && strings.HasPrefix(redirectTo, setting.AppSubUrl) {
203: 		redirectTo = strings.TrimPrefix(redirectTo, setting.AppSubUrl)
204: 	}
205: 
206: 	if redirectTo == "/" {
207: 		return ""
208: 	}
209: 
210: 	// remove any forceLogin=true params
211: 	redirectTo = removeForceLoginParams(redirectTo)
212: 	return "?redirectTo=" + url.QueryEscape(redirectTo)
213: }
