221: func newID() string {
222: 	// Less ambiguity than alphanumerical.
223: 	numerical := []byte("0123456789")
224: 	id, err := util.GetRandomString(10, numerical...)
225: 	if err != nil {
226: 		// this should not happen, but if it does, a timestamp is as
227: 		// useful as anything.
228: 		id = fmt.Sprintf("%d", time.Now().UnixNano())
229: 	}
230: 	return "ACE" + id
231: }
