235: func AuthorizeInOrgMiddleware(ac AccessControl, authnService authn.Service) func(OrgIDGetter, Evaluator) web.Handler {
236: 	return func(getTargetOrg OrgIDGetter, evaluator Evaluator) web.Handler {
237: 		return func(c *contextmodel.ReqContext) {
238: 			ctx, span := tracer.Start(c.Req.Context(), "accesscontrol.AuthorizeInOrgMiddleware")
239: 			defer span.End()
240: 			c.Req = c.Req.WithContext(ctx)
241: 
242: 			targetOrgID, err := getTargetOrg(c)
243: 			if err != nil {
244: 				if errors.Is(err, ErrInvalidRequestBody) || errors.Is(err, ErrInvalidRequest) {
245: 					c.JSON(http.StatusBadRequest, map[string]string{
246: 						"message": err.Error(),
247: 						"traceID": tracing.TraceIDFromContext(c.Req.Context(), false),
248: 					})
249: 					return
250: 				}
251: 				deny(c, nil, fmt.Errorf("failed to get target org: %w", err))
252: 				return
253: 			}
254: 
255: 			var orgUser identity.Requester = c.SignedInUser
256: 			if targetOrgID != c.GetOrgID() {
257: 				orgUser, err = authnService.ResolveIdentity(c.Req.Context(), targetOrgID, c.GetID())
258: 				if err == nil && orgUser.GetOrgID() == NoOrgID {
259: 					// User is not a member of the target org, so only their global permissions are relevant
260: 					orgUser, err = authnService.ResolveIdentity(c.Req.Context(), GlobalOrgID, c.GetID())
261: 				}
262: 				if err != nil {
263: 					deny(c, nil, fmt.Errorf("failed to authenticate user in target org: %w", err))
264: 					return
265: 				}
266: 			}
267: 			authorize(c, ac, orgUser, evaluator)
268: 
269: 			// guard against nil map
270: 			if c.Permissions == nil {
271: 				c.Permissions = make(map[int64]map[string][]string)
272: 			}
273: 			c.Permissions[orgUser.GetOrgID()] = orgUser.GetPermissions()
274: 		}
275: 	}
276: }
