307: // UseOrgFromRequestData returns the organization from the request data.
308: // If no org is specified, then the org where user is logged in is returned.
309: func UseOrgFromRequestData(c *contextmodel.ReqContext) (int64, error) {
310: 	query, err := getOrgQueryFromRequest(c)
311: 	if err != nil {
312: 		return NoOrgID, err
313: 	}
314: 
315: 	if query.OrgId == nil {
316: 		return c.GetOrgID(), nil
317: 	}
318: 
319: 	return *query.OrgId, nil
