322: // UseGlobalOrgFromRequestData returns global org if `global` flag is set or the org where user is logged in.
323: // If RBACSingleOrganization is set, the org where user is logged in is returned - this is intended only for cloud workflows, where instances are limited to a single organization.
324: func UseGlobalOrgFromRequestData(cfg *setting.Cfg) OrgIDGetter {
325: 	return func(c *contextmodel.ReqContext) (int64, error) {
326: 		query, err := getOrgQueryFromRequest(c)
327: 		if err != nil {
328: 			return NoOrgID, err
329: 		}
330: 
331: 		// We only check permissions in the global organization if we are not running a SingleOrganization setup
332: 		// That allows Organization Admins to modify global roles and make global assignments.
333: 		if query.Global && !cfg.RBAC.SingleOrganization {
334: 			return GlobalOrgID, nil
335: 		}
336: 
337: 		return c.GetOrgID(), nil
338: 	}
339: }
