343: 	return func(c *contextmodel.ReqContext) (int64, error) {
344: 		// We only check permissions in the global organization if we are not running a SingleOrganization setup
345: 		// That allows Organization Admins to modify global roles and make global assignments, and is intended for use in hosted Grafana.
346: 		if c.QueryBool("global") && !cfg.RBAC.SingleOrganization {
347: 			return GlobalOrgID, nil
