354: func getOrgQueryFromRequest(c *contextmodel.ReqContext) (*QueryWithOrg, error) {
355: 	query := &QueryWithOrg{}
356: 
357: 	req, err := CloneRequest(c.Req)
358: 	if err != nil {
359: 		return nil, err
360: 	}
361: 
362: 	if err := web.Bind(req, query); err != nil {
363: 		if err.Error() == "unexpected EOF" {
364: 			return nil, fmt.Errorf("%w: unexpected end of JSON input", ErrInvalidRequestBody)
365: 		}
366: 		return nil, ErrInvalidRequest.Errorf("error parsing request: %w", err)
367: 	}
368: 
369: 	return query, nil
370: }
