372: // CloneRequest creates request copy including request body
373: func CloneRequest(req *http.Request) (*http.Request, error) {
374: 	// Get copy of body to prevent error when reading closed body in request handler
375: 	bodyCopy, err := CopyRequestBody(req)
376: 	if err != nil {
377: 		return nil, err
378: 	}
379: 	reqCopy := req.Clone(req.Context())
380: 	reqCopy.Body = bodyCopy
381: 	return reqCopy, nil
382: }
383: 
384: // CopyRequestBody returns copy of request body and keeps the original one to prevent error when reading closed body
385: func CopyRequestBody(req *http.Request) (io.ReadCloser, error) {
386: 	if req.Body == nil {
387: 		return nil, nil
388: 	}
389: 
390: 	body := req.Body
391: 	var buf bytes.Buffer
392: 	if _, err := buf.ReadFrom(body); err != nil {
393: 		return nil, err
394: 	}
395: 	if err := body.Close(); err != nil {
396: 		return nil, err
397: 	}
398: 	req.Body = io.NopCloser(&buf)
399: 	return io.NopCloser(bytes.NewReader(buf.Bytes())), nil
400: }
