408: // scopeInjector inject request params into the templated scopes. e.g. "settings:" + eval.Parameters(":id")
409: func scopeInjector(params scopeParams) ScopeAttributeMutator {
410: 	return func(_ context.Context, scope string) ([]string, error) {
411: 		tmpl, err := template.New("scope").Parse(scope)
412: 		if err != nil {
413: 			return nil, err
414: 		}
415: 		var buf bytes.Buffer
416: 		if err = tmpl.Execute(&buf, params); err != nil {
417: 			return nil, err
418: 		}
419: 		return []string{buf.String()}, nil
420: 	}
421: }
